"""
MKT Original Commentary — Nehemiah chapters 11–12
Run: python3 scripts/zc-original-nehemiah-11-12.py

Source data used:
- data/interlinear/nehemiah.json
- data/translation/draft/mediating/nehemiah.json

Key decisions in this range:
- Ch 11 and 12 are dense list chapters; list-item verses receive brief entries
  noting the institutional role, Hebrew term, or structural significance
- Ch 12:27-43 (wall dedication) receives fuller treatment — this is the liturgical
  climax of the entire Nehemiah narrative
- 'ʿîr haqqōḏeš' (the holy city) is a rare designation preserved as-is
- tôḏāh covers both the abstract sense (thanksgiving) and the concrete liturgical
  sense (a choir appointed for thanksgiving); both senses are in play in ch12
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEHEMIAH = {
  "11": {
    "1": '<p><strong>gôrāl</strong> (<em>lot</em>) selects one in ten for Jerusalem. <strong>ʿîr haqqōḏeš</strong> — &#8220;the holy city&#8221; — appears only here and in v.18 in Nehemiah; the designation elevates Jerusalem from a ruined administrative center to a sacred space whose re-population is itself a religious obligation. The lottery distributes the burden of urban resettlement equitably; the city needs residents before it can function as the community&#8217;s center.</p>',
    "2": '<p><strong>hitnaddeḇ</strong> (<em>to volunteer willingly</em>) — the Hithpael of <em>nāḏaḇ</em>, meaning to offer oneself voluntarily; the same root as <em>nᵉḏāḇāh</em> (freewill offering). The community&#8217;s public praise of these volunteers signals the social honor attached to accepting the hardship of Jerusalem&#8217;s sparse urban life; moving to the city was a sacrifice, and the community registers it as such.</p>',
    "3": '<p>The genealogical register organizes Jerusalem&#8217;s inhabitants by institutional category: tribal (Judah, Benjamin), priestly, Levitical, temple servants. This five-category structure reproduces the pre-exilic temple-city administration — the restored community consciously reconstitutes the Davidic-Solomonic order rather than innovating a new structure.</p>',
    "4": '<p>Athaiah of the Perez line of Judah — Perez (<em>pereṣ</em>, &#8220;breach&#8221;) was the son of Judah and Tamar whose unexpected first birth (Gen 38:29) established the dominant Judahite sub-clan. The Perez genealogy recurs as a mark of Davidic legitimacy (Ruth 4:18-22; Matt 1:3).</p>',
    "5": '<p>Maaseiah of the Shilonite line — <em>Šîlōnî</em> may derive from Shiloh (the pre-Jerusalem sanctuary) or from Shelah, Judah&#8217;s third son; either way it is a minority Judahite lineage recorded alongside the dominant Perez clan, signaling that the restored city population preserves the full genealogical breadth of the tribe.</p>',
    "6": '<p><strong>ʾanšê ḥayil</strong> — &#8220;capable men&#8221; or &#8220;men of valor&#8221;; 468 from the Perez line alone. <em>ḥayil</em> spans military prowess, social capability, and economic substance — the same term used for the &#8220;woman of valor&#8221; in Prov 31:10. Its use here marks the Jerusalem settlers as a capable, capable class, not a residual remnant.</p>',
    "7": '<p>Sallu of the Meshullam line from Benjamin — the genealogy traces back six generations, anchoring the Benjaminite settlers within their known pre-exilic clan structures. The depth of the genealogy signals legitimate continuity with the pre-exilic community.</p>',
    "8": '<p>Gabbai and Sallai add to the Benjaminite total: 928 settlers from Benjamin in Jerusalem. The tribe of Benjamin&#8217;s significant representation reflects that Jerusalem fell within Benjamin&#8217;s tribal territory in the original allocation (Josh 18:28); their presence in the city has both genealogical and territorial legitimacy.</p>',
    "9": '<p><strong>pāqîḏ</strong> (<em>overseer</em>) and <em>mišneh</em> (<em>second-in-command</em>) — the dual-leadership structure mirrors the city&#8217;s administrative organization; Joel oversees the Benjaminites while Judah son of Senuah is second over the city as a whole. The term <em>mišneh</em> (second) is the same used for the &#8220;second quarter&#8221; of Jerusalem (Zeph 1:10) and for the second-in-command to the king (2 Chr 28:7).</p>',
    "10": '<p>Jedaiah son of Joiarib and Jachin — two priestly family heads whose names recur throughout the restoration records. Joiarib&#8217;s family is listed first (also in 1 Chr 24:7) and will later produce the Maccabean priests; Jachin was one of the two pillars of Solomon&#8217;s temple (1 Kgs 7:21).</p>',
    "11": '<p>Seraiah as <strong>śar bêṯ-hāʾĕlōhîm</strong> — &#8220;officer/prince of the house of God&#8221; — the chief administrative officer of the temple; the term <em>śar</em> indicates a position of governing authority. The genealogy traces through Zadok, establishing that the chief priest of the restored temple continues the Zadokite line that Ezekiel&#8217;s temple vision required (Ezek 44:15).</p>',
    "12": '<p>822 relatives serving in the temple — the largest priestly contingent listed. Their service is described as <em>ʿōśê hamᵉlāʾḵāh labayiṯ</em> (&#8220;doing the work of the house&#8221;) — the same term for the temple work that David organized and Solomon executed; the verb-noun pair carries continuity with the pre-exilic cult.</p>',
    "13": '<p>Adaiah leads 242 heads of ancestral houses — <em>rāʾšê ʾāḇôṯ</em> (&#8220;heads of fathers&#8217; houses&#8221;) is the administrative term for family-clan leaders who bear responsibility for the entire extended household. The relatively small number (242) compared to the total suggests these are senior representatives, not the full priestly count.</p>',
    "14": '<p>128 <strong>ʾanšê ḥayil</strong> under Zabdiel — the &#8220;men of valor&#8221; designation applied to priests signals a martial-administrative quality alongside the cultic function; priests in the post-exilic community sometimes combined cultic and civic leadership. The name Zabdiel means &#8220;gift of God&#8221; (<em>zeḇaḏ ʾēl</em>).</p>',
    "15": '<p>The Levitical register begins with Shemaiah, tracing back to Bunni — one of the Levites who sealed the covenant in Neh 10:9. The depth of Levitical genealogies varies: some trace four-five generations, others only two, reflecting varying states of record-preservation after the exile.</p>',
    "16": '<p>Shabbethai and Jozabad are over <strong>hamᵉlāʾkāh haḥîṣônāh</strong> — &#8220;the external work/affairs of the house of God&#8221;; this likely covers administration, procurement, and oversight functions outside the sanctuary itself, as distinct from the cultic Levitical duties performed within. The division between internal sanctuary service and external administrative work mirrors the Chronicler&#8217;s organization of Levitical duties (1 Chr 23).</p>',
    "17": '<p>Mattaniah &#8220;who directed the <strong>hôḏāʾāh</strong> in prayer&#8221; — <em>hôḏāʾāh</em> is the noun from <em>yāḏāh</em> (to give thanks, to praise); Mattaniah leads the community&#8217;s formal thanksgiving liturgy, an Asaphite function (his line traces to Asaph, David&#8217;s chief musician); Bakbukiah is his counterpart leading the antiphonal response. The thanking/praising function is the Levitical role most directly continued into NT worship (Col 3:16).</p>',
    "18": '<p>284 Levites total in Jerusalem — a relatively small number for a city that requires their full temple ministry. The scarcity of Levites willing to return from Babylon was a recurring problem (Ezra 8:15-20 records Ezra having to specifically recruit Levites who had not come); those listed here represent the committed core.</p>',
    "19": '<p>172 gatekeepers — <strong>šōʿᵃrîm</strong> (those who guard the gates). The gatekeepers&#8217; function was both cultic (guarding the temple gates) and civic (controlling access to the city); the restoration of this role is part of the normalization of Jerusalem as a functioning city-sanctuary after the wall&#8217;s completion.</p>',
    "20": '<p>The priests and Levites outside Jerusalem lived in their ancestral towns — <em>naḥᵃlāṯô</em> (his inheritance); the ancestral land-holding system is preserved even for those serving in the temple. The Levitical towns assigned in Joshua 21 are the legal basis for this dispersal, though many towns had been redistributed or occupied during the exile.</p>',
    "21": '<p>The <strong>nᵉṯînîm</strong> (temple servants) on the Ophel — the hill south of the temple mount. The <em>nᵉṯînîm</em> were subordinate temple workers, perhaps descendants of prisoners of war given (<em>nāṯan</em> = given) to temple service; their placement on the Ophel rather than within the city walls proper reflects their lower social status within the cultic hierarchy.</p>',
    "22": '<p>Uzzi the overseer of Levites in Jerusalem — traced as an Asaphite, the family of David&#8217;s chief musician. The Asaphites&#8217; prominence in both the pre-exilic and post-exilic periods signals the continuity of David&#8217;s musical institution; the restored temple&#8217;s musical life is not an innovation but a recovery.</p>',
    "23": '<p><strong>dāḇar hammelek</strong> — &#8220;the king&#8217;s decree/command&#8221;; the Persian royal court provided a fixed daily portion (<em>ḥōq-yôm bᵉyômô</em>) for the singers, subsidizing the temple music program. This is the same Persian administrative generosity that funded the temple rebuilding (Ezra 6:8-10); the empire&#8217;s patronage of the temple musicians reflects the Persian policy of supporting local cultic practices as a tool of imperial stability.</p>',
    "24": '<p>Pethahiah as <strong>yāḏ lammelek</strong> — literally &#8220;hand to the king&#8221; — the Persian royal liaison for community affairs; he is from the Zerah line of Judah (the other main Judahite clan after Perez). This liaison role represents the Jewish community&#8217;s formal interface with the Persian administration, a position requiring both cultural fluency and community trust.</p>',
    "25": '<p>The village settlements of Judah begin with Kiriath-arba (the ancient name for Hebron, Gen 23:2) — a city with deep patriarchal associations (Abraham purchased land there). Mentioning Kiriath-arba rather than Hebron may be a deliberate archaism that claims the oldest layer of Israelite territorial presence.</p>',
    "26": '<p>Jeshua and Moladah are towns in the Negev region. Moladah (&#8220;birth&#8221;) was listed in Josh 15:26 as a Judahite town and in Josh 19:2 as Simeonite — the overlapping claims reflect the fluid tribal boundaries of the far south. The restoration community is reoccupying the full territorial extent of pre-exilic Judah, not just the Jerusalem core.</p>',
    "27": '<p>Beersheba — <em>bᵉʾēr šeḇaʿ</em> (well of seven/oath) — the southern boundary marker of Israel in the common phrase &#8220;from Dan to Beersheba.&#8221; Its inclusion in the resettlement signals the community&#8217;s ambition to restore the full extent of historical Judah, including the peripheral southern region that was the least likely to have survived the Babylonian deportation with any continuity.</p>',
    "28": '<p>Ziklag is David&#8217;s Philistine base of operations before becoming king (1 Sam 27:6); its inclusion among the resettled towns claims the full western territory associated with the Davidic kingdom. The list moves from the Negev (Beersheba) across to former Philistine borderland.</p>',
    "29": '<p>En-rimmon, Zorah, and Jarmuth — En-rimmon in the Negev; Zorah is Samson&#8217;s home territory (Judg 13:2); Jarmuth is listed as a royal Canaanite city defeated by Joshua (Josh 10:3). The recitation of these towns implicitly reclaims the entire pre-Babylonian territorial inheritance.</p>',
    "30": '<p>The settlement range: &#8220;from Beersheba all the way to the Valley of Hinnom&#8221; — the southern extent to the valley just outside Jerusalem&#8217;s south wall. <em>Gê-hinnom</em> (Valley of Hinnom) was the site of Molech worship that Josiah defiled (2 Kgs 23:10); its presence on the southern boundary is a reminder of the cult-sites the restoration must leave purified.</p>',
    "31": '<p>The Benjaminite settlements begin at Geba — <em>Geḇaʿ</em> (hill), a Levitical town north of Jerusalem. Michmash was the site of Jonathan&#8217;s famous single-handed victory (1 Sam 14); Bethel, though long associated with Jeroboam&#8217;s rival worship, is reclaimed as a Benjaminite settlement site.</p>',
    "32": '<p>Anathoth — the Levitical city of Jeremiah&#8217;s origin (Jer 1:1); its inclusion in the resettlement list means the community settling Anathoth is returning to the city whose son had warned most urgently about the exile they have just survived. Nob was the priestly city massacred by Saul (1 Sam 22:19).</p>',
    "33": '<p>Hazor and Ramah — Ramah was the site of Samuel&#8217;s home, school, and burial (1 Sam 7:17; 25:1); Gittaim appears in 2 Sam 4:3 as the refuge of Beerothites who fled during the civil war period. The Benjaminite resettlement names echo the entire narrative range of the pre-exilic period.</p>',
    "34": '<p>Hadid and Zeboim — Hadid reappears in the return lists (Ezra 2:33; Neh 7:37); Zeboim means &#8220;hyenas&#8221; — a topographic name for a rugged ravine area northeast of Jerusalem. These are smaller settlements filling out the Benjaminite territory north of the city.</p>',
    "35": '<p>Lod and Ono in the &#8220;Valley of Craftsmen&#8221; (<em>gê-hāḥarāšîm</em>) — this valley, where artisans had apparently concentrated, is the only explicitly occupational place-name in the list. 1 Chr 4:14 attributes the founding of this &#8220;valley of craftsmen&#8221; to a descendant of Judah (Joab), though it falls in Benjaminite territory here.</p>',
    "36": '<p>Some Levitical divisions from Judah were assigned to Benjamin — the Levites did not hold tribal territory but were distributed across both tribes&#8217; settlements. This final note emphasizes that the Levitical presence extends the religious infrastructure across the full settlement area, not just in Jerusalem proper.</p>',
  },
  "12": {
    "1": '<p>The priestly list returns to the first return under Zerubbabel (ca. 538 BCE), a generation before Nehemiah. Seraiah leads the list — the same Seraiah lineage that appears in ch11:11 as the chief officer of the temple. Jeremiah and Ezra appear as priestly family names (not the prophets), demonstrating the name&#8217;s common use in priestly circles.</p>',
    "2": '<p>Amariah, Malluch, Hattush — three priestly family heads; Hattush is also listed as a returnee in Ezra 8:2 among those who came with Ezra, suggesting this list preserves both first-return and second-return lineages. The overlap reinforces the continuity of the priestly institution across the two return waves.</p>',
    "3": '<p>Shechaniah, Rehum, Meremoth — Rehum appears as a builder in Neh 3:17; Meremoth son of Uriah is the priest who received the silver and gold from Ezra&#8217;s caravan (Ezra 8:33). The priestly list and the narrative are populated by the same families — the same clans who built the walls also maintain the cultic records.</p>',
    "4": '<p>Iddo, Ginnetho, Abijah — Iddo is the grandfather of the prophet Zechariah (Zech 1:1), whose family was one of the priestly clans; Zechariah the prophet is thus of priestly descent as well as prophetic calling. Abijah is the priestly division to which John the Baptist&#8217;s father Zechariah belonged (Luke 1:5), the eighth of the twenty-four Davidic divisions.</p>',
    "5": '<p>Miamin, Maadiah, Bilgah — minor priestly families preserved in the roster. The detailed record-keeping across multiple generations (the first return, then v.12-21 traces the next generation) reflects the priestly community&#8217;s careful management of genealogical continuity, essential for maintaining Aaronic legitimacy.</p>',
    "6": '<p>Shemaiah, Joiarib, Jedaiah — the three leading priestly families; Joiarib heads the list of 24 priestly divisions in 1 Chr 24:7 and is the Maccabean priestly family&#8217;s ancestor (1 Macc 2:1). Jedaiah is consistently listed among the most prominent post-exilic priestly families (Ezra 2:36; Neh 7:39).</p>',
    "7": '<p>&#8220;These were the leading priests and their associates in the days of Jeshua&#8221; — the list is anchored to the first high priest of the return, Jeshua son of Jozadak (Ezra 3:2; Hag 1:1; Zech 3:1), establishing that the priestly institution of Nehemiah&#8217;s day is the direct descendant of the community that Zerubbabel led back.</p>',
    "8": '<p>The Levitical list with Jeshua, Binnui, Kadmiel, Sherebiah, Judah, and Mattaniah — these names recur throughout the restoration records (Ezra 2:40; Neh 8:7; 9:4-5) as the core Levitical clans of the return. Mattaniah &#8220;with his brothers led the songs of thanksgiving&#8221; — the <em>hôḏāʾôṯ</em> function described also in 11:17; the Levitical music tradition is consistent across both lists.</p>',
    "9": '<p>Bakbukiah and Unni &#8220;stood opposite them during the service watches&#8221; — <em>lᵉneḡḏām</em> (opposite/facing them) describes the antiphonal arrangement of two Levitical choirs facing each other, the arrangement underlying the responsive structure of many Psalms. The &#8220;service watches&#8221; (<em>mišmārôṯ</em>) organized Levitical ministry into rotating schedules.</p>',
    "10": '<p>Jeshua fathered Joiakim — the high priestly succession: five generations are traced from the first post-exilic high priest (Jeshua) through to Jaddua. This genealogy is historically important as it extends the known high priestly sequence; Josephus mentions Jaddua as high priest when Alexander the Great visited Jerusalem (ca. 332 BCE), suggesting this list extends to the late Persian period.</p>',
    "11": '<p>Jonathan fathered Jaddua — the final generation listed; the succession Jeshua → Joiakim → Eliashib → Joiada → Jonathan → Jaddua spans roughly 538-332 BCE, approximately 200 years of priestly succession. Each generation represents the institutional continuity of the Aaronic line through the Persian period.</p>',
    "12": '<p>The second-generation priestly list (&#8220;in the days of Joiakim&#8221;) pairs each priestly family with its head in the following generation. <em>Meraiah</em> from Seraiah&#8217;s line — the naming pattern of son-of-the-same-root is common (Seraiah → Meraiah both from the same root <em>śārāh</em>/<em>mārāh</em>). These family-head lists are the administrative records of the priestly rotation system.</p>',
    "13": '<p>Meshullam from Ezra&#8217;s line — whether this is the priestly family whose ancestor was the Ezra of v.1 (not the scribe Ezra who came later) or the scribe Ezra himself cannot be determined from the list. The priestly register preserves multiple Meshullams (one seals the covenant in Neh 10:7) — the name means &#8220;repaid/restored.&#8221;</p>',
    "14": '<p>Jonathan from Malluch&#8217;s line; Joseph from Shebaniah&#8217;s line — the priestly family register continues through the mid-Persian period. The variety of names reflects the priestly community&#8217;s demographic depth; these are not a handful of elite families but a substantial roster of clans maintaining the rotation schedule.</p>',
    "15": '<p>Adna from Harim&#8217;s line — Harim is a prominent priestly family in the return lists (Ezra 2:39: 1,017 returnees; the largest single priestly group). Helkai from Meraioth&#8217;s line — <em>Merāyôṯ</em> traces through the Zadokite genealogy (1 Chr 6:6-7), reinforcing Zadokite legitimacy for the post-exilic temple.</p>',
    "16": '<p>Zechariah from Iddo&#8217;s line — this Zechariah is almost certainly the prophet Zechariah son of Berechiah son of Iddo (Zech 1:1), making the prophet&#8217;s dual identity as priest and prophet explicit. The prophet who proclaimed &#8220;not by might, not by power, but by my Spirit&#8221; (Zech 4:6) to the temple-rebuilding community also served in the priestly roster.</p>',
    "17": '<p>Zichri from Abijah&#8217;s line — Abijah was the priestly division of Zechariah son of Barachiah (not the prophet; Luke 1:5 places John the Baptist&#8217;s father Zechariah in this division). The Abijah division is the eighth of the twenty-four (1 Chr 24:10), which establishes the timing of Zechariah&#8217;s service when Gabriel appeared to him.</p>',
    "18": '<p>Shammua from Bilgah&#8217;s line; Jehonathan from Shemaiah&#8217;s line — Shemaiah is the family head whose ancestor Shemaiah appears in v.6 as one of the leading priests of Jeshua&#8217;s generation. The continuity across two generations within a list chapter demonstrates the priestly community&#8217;s investment in genealogical memory.</p>',
    "19": '<p>Mattenai from Joiarib&#8217;s line — Joiarib, the first of the 24 priestly divisions (1 Chr 24:7), is the Maccabean priestly family&#8217;s ancestor; the registration of this line here in the Persian-period records is the genealogical basis for the Maccabees&#8217; priestly legitimacy claim two centuries later.</p>',
    "20": '<p>Kallai from Sallai&#8217;s line; Eber from Amok&#8217;s line — minor priestly families; Amok means &#8220;deep&#8221; or &#8220;inscrutable,&#8221; possibly a title. These smaller families fill out the roster of the 24 priestly divisions that David established (1 Chr 24) and that the post-exilic community works to reconstitute.</p>',
    "21": '<p>Hashabiah from Hilkiah&#8217;s line; Nethanel from Jedaiah&#8217;s line — Jedaiah&#8217;s line is the second priestly division (1 Chr 24:7) and one of the most prominent in the return records. These final entries complete the second-generation priestly register, covering all the priestly families who returned to serve in the restored temple.</p>',
    "22": '<p>The Levitical family heads are registered under four successive high priests: Eliashib, Joiada, Johanan, and Jaddua. The mention of &#8220;down to the reign of Darius the Persian&#8221; — likely Darius II (423-404 BCE) or Darius III (336-330 BCE) — indicates the register covers approximately a century of Levitical genealogy after the initial return.</p>',
    "23": '<p>The records are preserved in <em>sēper diḇrê hayyāmîm</em> — &#8220;the Book of the Chronicles/Days,&#8221; an administrative record distinct from the canonical Chronicles; such administrative registers (<em>diḇrê hayyāmîm</em>) were standard Persian-period archival practice. The reference gives the archival basis for the list&#8217;s authority — this is not oral memory but documented record.</p>',
    "24": '<p>&#8220;As David the man of God had commanded&#8221; — <strong>ʾîš hāʾĕlōhîm</strong> (man of God) applied to David is unusual; it appears only here and in 2 Chr 8:14. The title elevates David&#8217;s musical and liturgical organization to the level of prophetic command, equivalent in authority to Moses&#8217; legislative commands — thus the post-exilic Levitical antiphonal arrangement is not human tradition but divine instruction mediated through David.</p>',
    "25": '<p>The gatekeepers Mattaniah, Bakbukiah, Obadiah, Meshullam, Talmon, and Akkub — Talmon and Akkub appear in the first-return list (Ezra 2:42; Neh 7:45), meaning the gatekeeper families maintained their institutional identity across generations. <em>ʾōṣᵃrôṯ</em> (storerooms) beside the gates housed tithes, offerings, and temple utensils; the gatekeepers doubled as guardians of these stores.</p>',
    "26": '<p>The dual dating — &#8220;in the days of Joiakim... and in the days of Nehemiah the governor and Ezra the priest and scribe&#8221; — anchors this entire register to two periods: the generation after the return and Nehemiah&#8217;s own administration. The pairing of Nehemiah (civil leader) and Ezra (priestly-scribal authority) names the dual leadership structure of the restoration community explicitly.</p>',
    "27": '<p><strong>ḥᵃnukkaṯ</strong> (<em>dedication</em>) — the root <em>ḥānaḵ</em> means to dedicate/inaugurate; the same root gives <em>Hanukkah</em>, the later festival commemorating the re-dedication of the temple after Antiochus IV&#8217;s desecration (165 BCE). The wall&#8217;s dedication ceremony is a <em>ḥᵃnukkāh</em> in the full sense: a formal liturgical act of consecrating the structure to YHWH&#8217;s purposes, not merely a civic celebration. The Levites are gathered from all their towns — the entire worship apparatus is mobilized for this single ceremony.</p>',
    "28": '<p>The singers&#8217; guilds (<em>bᵉnê hammᵉšōrᵃrîm</em>) gather from Netophah and the surrounding villages. Netophah appears in the return lists (Ezra 2:22; Neh 7:26) and is known from 2 Sam 23:28-29 as home to two of David&#8217;s thirty mighty men. The singers had established their own villages (<em>ḥaṣêrôṯ</em>) — residential clusters — around Jerusalem, maintaining the musical institution as a semi-permanent settlement.</p>',
    "29": '<p>Beth-gilgal — likely near the original Gilgal where Israel camped after crossing the Jordan (Josh 4:19), the place of covenant renewal at the conquest. The singers coming from Gilgal territory adds a covenantal resonance to the dedication procession — the worship that begins at the Jordan entry point converges on Jerusalem.</p>',
    "30": '<p><strong>wayyiṭṭahᵃrû</strong> (<em>they purified themselves</em>) — ritual purification before the dedication: the priests and Levites first purify themselves (<em>ṭāhēr</em>), then purify the people, then the gates, then the wall. The sequence moves outward from the cultic personnel to the architectural structure, a comprehensive sanctification that transforms Jerusalem&#8217;s rebuilt infrastructure into sacred space. The gates and wall are not merely civic engineering — they become holy by this act.</p>',
    "31": '<p>Two <strong>tôḏôṯ</strong> (thanksgiving choirs, plural of <em>tôḏāh</em>) proceed in opposite directions around the wall. <em>tôḏāh</em> covers both the abstract sense (an act of thanksgiving) and the concrete liturgical sense (a choir appointed for thanksgiving); in Lev 7:12 it is also a type of peace offering. The two processions are designed to meet at the temple — the wall&#8217;s dedication is enacted by the community physically circumambulating it while singing, transforming the defensive structure into a liturgical boundary.</p>',
    "32": '<p>Hoshaiah leads the first thanksgiving choir with half the leaders of Judah. The procession route described in vv.31-37 moves from the Dung Gate (south) eastward along the south wall — the route passes the poorest, most ruined section of the city, now restored. The leaders of Judah (civil authorities) march with the liturgical procession, signaling that the wall&#8217;s dedication is a civic-religious act, not just a temple ceremony.</p>',
    "33": '<p>Azariah, Ezra, and Meshullam — Ezra the scribe marches in the liturgical procession that Nehemiah has organized; the civic and scribal-priestly leadership are united in the ceremony. The same Ezra who read the law before the people (ch8) now walks the wall&#8217;s perimeter, embodying the integration of word and work in the restoration project.</p>',
    "34": '<p>Judah, Benjamin, Shemaiah, and Jeremiah — the tribal representatives (Judah and Benjamin) march alongside the priestly figures, symbolizing the whole community in both its civil-tribal and cultic dimensions. The dedication is not a priestly ceremony that the people observe; it is the community&#8217;s collective liturgical act.</p>',
    "35": '<p>The trumpeting priests with Zechariah son of Jonathan — <em>ḥăṣōṣᵃrôṯ</em> (trumpets) were the priestly instruments (Num 10:2-10), distinct from the Levitical harps and lyres; their sounding marks the procession as a sacred assembly in the same category as the wilderness camp&#8217;s trumpet calls. Zechariah&#8217;s seven-generation genealogy traces through Asaph, anchoring the trumpet-players in the Davidic musical institution.</p>',
    "36": '<p>The musical instruments of <strong>ʾîš hāʾĕlōhîm</strong> — &#8220;David the man of God&#8221; (the same title as in v.24); the specific instruments played at the dedication are identified as those David prescribed. Ezra the scribe leads the way for this first choir — the one responsible for the community&#8217;s Torah instruction is the liturgical guide for the wall&#8217;s circumambulation.</p>',
    "37": '<p>The Fountain Gate, the stairs of the City of David, the house of David, the Water Gate — the procession route traces the eastern slope of Jerusalem, the oldest inhabited area, following the topography of the Davidic city. The Fountain Gate (<em>šaʿar hāʿayin</em>) gave access to the Gihon spring, Jerusalem&#8217;s water supply, which David had used to take the city (2 Sam 5:8).</p>',
    "38": '<p>The second thanksgiving choir moves in the opposite direction — west and north around the wall — with Nehemiah and half the people. The two processions are synchronized to converge at the temple mount; the entire wall perimeter is covered, not just the ceremonial sections. Nehemiah&#8217;s participation places the civil governor within the liturgical act — governance and worship are integrated in the ceremony.</p>',
    "39": '<p>The route of the second choir: Gate of Ephraim (the north gate toward Ephraim/Samaria), Old Gate, Fish Gate, Tower of Hananel, Tower of the Hundred, Sheep Gate, Gate of the Guard. These gates were repaired by specific teams in ch3; the dedication procession now consecrates each repaired structure by passing through or around it, completing the narrative arc from construction to consecration.</p>',
    "40": '<p>Both thanksgiving choirs take their places in the house of God — the procession that began at the wall converges in the temple. The ceremony moves from the circumference (wall) to the center (temple), enacting in liturgical geography the relationship between the city and its sanctuary: the wall exists to protect and serve the temple&#8217;s worship.</p>',
    "41": '<p>Seven priestly trumpeters are named — the number seven is structurally significant in priestly ceremonial contexts (Lev 14:7; Josh 6:4). The seven trumpeters parallel the Jericho narrative where seven priests with seven trumpets circled the city: Jerusalem&#8217;s wall dedication deliberately echoes the conquest&#8217;s wall demolition, this time with consecration rather than destruction.</p>',
    "42": '<p>The singers sang loudly under Jezrahiah — <em>wayyaśmîʿû</em> (they made [themselves] heard, Hiphil of <em>šāmaʿ</em>) — under Jezrahiah their &#8220;director&#8221; (<em>pāqîḏ</em>, the same term as &#8220;overseer&#8221;). The full vocal performance unites with the trumpets and instruments; the dedication is primarily an auditory ceremony, not a visual spectacle — the community fills Jerusalem with sound.</p>',
    "43": '<p><strong>śimḥāh gᵉḏôlāh</strong> — the phrase &#8220;great joy&#8221; is used five times in this verse in three different forms: <em>wayiśmaḥû</em> (they rejoiced), <em>śimḥāh gᵉḏôlāh</em> (great joy), <em>wayyiśmᵉḥû</em> (they rejoiced), <em>wayyaśmîaḥ</em> (he caused to rejoice), and the final <em>wattišmaʿ</em> (it was heard). The cascading joy expressions are the narrator&#8217;s literary signature for the moment when YHWH&#8217;s purposes are visibly accomplished; the same intensity appears at the dedication of Solomon&#8217;s temple (1 Kgs 8:66). &#8220;The sound of Jerusalem&#8217;s joy was heard far away&#8221; — the joy that the enemies tried to prevent has become the dominant sound of the region.</p>',
    "44": '<p>Appointments for the storeroom oversight — <em>gizāḇārôṯ</em> (treasuries) — consolidate the tithes, firstfruits, and contributions that ch13 will show were being neglected. The appointment occurs &#8220;that same day&#8221; as the dedication, linking the liturgical celebration directly to the institutional structures that sustain it. &#8220;Judah rejoiced in the priests and Levites who were serving&#8221; — the people&#8217;s delight in their ministers is the emotional counterpart to the dedication&#8217;s joy.</p>',
    "45": '<p>&#8220;As David and his son Solomon had commanded&#8221; — the restoration of Levitical service according to the Davidic-Solomonic pattern is the recurring legitimating appeal of the post-exilic community. The <em>mišmeret</em> (service-watch, guarding obligation) of singers and gatekeepers includes both the positive duty (performing the liturgy) and the negative duty (the requirements of purification — keeping the sacred space clean).</p>',
    "46": '<p>&#8220;In the days of David and Asaph, long ago, there had been <em>rāʾšê</em> (heads/directors) of the singers and songs of praise and thanksgiving to God&#8221; — the historical depth is explicit: the current Levitical music is a recovery of an institution that is as old as David himself. <em>Āsāp̄</em> (Asaph) is the named founder of the guilded singer tradition whose descendants appear throughout these chapters; his Psalms (Pss 50, 73-83) survive as evidence of this tradition.</p>',
    "47": '<p>Daily portions (<strong>mᵉnāyôt</strong>) set apart for the singers and gatekeepers — <em>mānāh</em> (portion/allotment) is the term for the divinely-determined or institutionally-assigned share; the same word for the &#8220;portions&#8221; Esther sends (Esth 9:19, 22). &#8220;They set apart what was holy for the Levites, and the Levites set apart what was holy for the descendants of Aaron&#8221; — the tithe-of-the-tithe principle (Num 18:26) is in operation: Israel tithes to the Levites, and the Levites tithe to the priests. The chapter ends with this institutional provision, the economic infrastructure that makes the worship of vv.27-43 sustainable.</p>',
  }
}

def main():
    existing = load_comm('mkt-original', 'nehemiah')
    merge_comm(existing, NEHEMIAH)
    save_comm('mkt-original', 'nehemiah', existing)
    print('Nehemiah 11-12 mkt-original written.')

if __name__ == '__main__':
    main()
